mapper.update:
UPDATE company
SET company_code    = #{companyCode}
  , company_name    = #{companyName}
  , business_no     = #{businessNo}
  , id_placeholder  = #{idPlaceHolder}
  , pw_type         = #{pwType}
  , no_use          = #{noUse}
  , use_noti_talk   = #{useNotiTalk}
  , ci_filename     = #{ciFilename}
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
  , account_user_id = #{accountUserId}
  , admin_user_id   = #{adminUserId}
  , sales_user_id   = #{salesUserId}
WHERE company_id = #{companyId}

UPDATE company
SET ci_filename     = NULL
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE company_id = #{companyId}

UPDATE company_checkup
SET employee_number             = #{employeeNumber}
  , family_number               = #{familyNumber}
  , checkup_date_begin          = #{checkupDateBegin}
  , checkup_date_end            = #{checkupDateEnd}
  , reserve_date_begin          = #{reserveDateBegin}
  , reserve_date_end            = #{reserveDateEnd}
  , expected_total_support_pay  = #{expectedTotalSupportPay}
  , expected_total_platform_pay = #{expectedTotalPlatformPay}
  , expected_total_etc_pay      = #{expectedTotalEtcPay}
  , sales_manager               = #{salesManager}
  , assist_manager              = #{assistManager}
  , notes                       = #{notes}
  , updated_at                  = NOW()
  , updated_user_id             = #{sessionUserId}
WHERE company_checkup_id = #{companyCheckupId}

UPDATE company_checkup_type
SET company_checkup_type_code = #{companyCheckupTypeCode}
  , company_checkup_type_name = #{companyCheckupTypeName}
  , support_pay               = #{supportPay}
  , copay                     = #{copay}
  , hospital_pay              = #{hospitalPay}
  , platform_pay              = #{platformPay}
  , type_self                 = #{typeSelf}
  , type_family               = #{typeFamily}
  , type_copay                = #{typeCopay}
  , updated_at                = NOW()
  , updated_user_id           = #{sessionUserId}
WHERE company_checkup_type_id = #{companyCheckupTypeId}

UPDATE company
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE company_id = #{companyId}

UPDATE company_checkup
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE company_checkup_id = #{companyCheckupId}

UPDATE company_checkup_type
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE company_checkup_type_id = #{companyCheckupTypeId}

